proptest! {
    /// Property: Mouse event converts between formats correctly
    #[test]
    fn mouse_format_conversion_roundtrip(
        event in arb_sgr_mouse_event()
    ) {
        // Only test coordinates that fit in X10 range
        prop_assume!(event.x <= 223 && event.y <= 223);
        prop_assume!(!event.is_release());  // X10 doesn't support release

        let sgr_bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&sgr_bytes).unwrap();

        // Convert to X10
        let x10_bytes = parsed.to_x10_bytes();
        let (x10_parsed, _) = MouseParser::parse(&x10_bytes).unwrap();

        // Core fields should match
        prop_assert_eq!(parsed.button, x10_parsed.button);
        prop_assert_eq!(parsed.x, x10_parsed.x);
        prop_assert_eq!(parsed.y, x10_parsed.y);
    }
}
