### 2. Session Manager Tests
```rust
#[cfg(test)]
mod session_tests {
    use super::*;

    #[tokio::test]
    async fn test_create_session() {
        let manager = SessionManager::new(10, Duration::from_secs(3600));

        let (id, _) = manager.create_session(
            "testuser".to_string(),
            "127.0.0.1:12345".parse().unwrap(),
        ).await.unwrap();

        assert!(manager.get_session(id).await.is_some());
    }

    #[tokio::test]
    async fn test_max_sessions_limit() {
        let manager = SessionManager::new(2, Duration::from_secs(3600));

        // Create max sessions
        manager.create_session("user1".into(), addr()).await.unwrap();
        manager.create_session("user2".into(), addr()).await.unwrap();

        // Third should fail
        let result = manager.create_session("user3".into(), addr()).await;
        assert!(matches!(result, Err(WishError::MaxSessionsReached)));
    }

    #[tokio::test]
    async fn test_session_removal() {
        let manager = SessionManager::new(10, Duration::from_secs(3600));
        let (id, _) = manager.create_session("user".into(), addr()).await.unwrap();

        manager.remove_session(id).await;

        assert!(manager.get_session(id).await.is_none());
    }

    #[tokio::test]
    async fn test_stale_session_cleanup() {
        let manager = SessionManager::new(10, Duration::from_millis(100));
        let (id, _) = manager.create_session("user".into(), addr()).await.unwrap();

        // Wait for timeout
        tokio::time::sleep(Duration::from_millis(150)).await;

        manager.cleanup_stale_sessions().await;

        assert!(manager.get_session(id).await.is_none());
    }
}
