# Using charmed_rust with React

## Installation

\`\`\`bash
npm install @charmed/wasm
\`\`\`

## Setup

\`\`\`tsx
// src/charmed.ts
import init, { Style, newStyle } from '@charmed/wasm';

let initialized = false;

export async function initCharmed() {
  if (!initialized) {
    await init();
    initialized = true;
  }
}

export { Style, newStyle };
\`\`\`

## Hook for Styled Content

\`\`\`tsx
// src/hooks/useCharmedStyle.ts
import { useState, useEffect } from 'react';
import { initCharmed, newStyle } from '../charmed';

export function useCharmedStyle() {
  const [ready, setReady] = useState(false);

  useEffect(() => {
    initCharmed().then(() => setReady(true));
  }, []);

  return { ready, newStyle: ready ? newStyle : null };
}
\`\`\`

## Component Example

\`\`\`tsx
// src/components/StyledBox.tsx
import { useCharmedStyle } from '../hooks/useCharmedStyle';

interface Props {
  children: string;
  color?: string;
  bold?: boolean;
}

export function StyledBox({ children, color = "#61dafb", bold = false }: Props) {
  const { ready, newStyle } = useCharmedStyle();

  if (!ready || !newStyle) {
    return <span>{children}</span>;
  }

  let style = newStyle().foreground(color);
  if (bold) {
    style = style.bold();
  }

  return (
    <span dangerouslySetInnerHTML={{ __html: style.render(children) }} />
  );
}
\`\`\`

## Server-Side Rendering (Next.js)

\`\`\`tsx
// pages/index.tsx
import dynamic from 'next/dynamic';

// Load component only on client side
const StyledBox = dynamic(
  () => import('../components/StyledBox').then(mod => mod.StyledBox),
  { ssr: false, loading: () => <span>Loading...</span> }
);

export default function Home() {
  return (
    <div>
      <StyledBox color="#ff6b6b" bold>
        Hello from charmed_rust!
      </StyledBox>
    </div>
  );
}
\`\`\`
